  ('locality-814ced5a-moex-00067', 'locality-814ced5a', 'locality-814ced5a-moex-111-b3f42868', 'sub-locality-814ced5a-02', NULL, 'single_choice', '甲為全國不分區立法委員，乙為區域立法委員，兩人皆屬A政黨，但因理念不合於近日宣布退黨。依 我國相關規定，下列何者為後續最可能的發展結果？', '["甲席次由A黨不分區立法委員名單中遞補", "乙席次由該分區第二高票候選人遞補", "甲成為無黨籍立法委員，乙席次重新辦理改選", "甲席次重新辦理改選，乙成為無黨籍立法委員"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:28+00:00", "source_pdf_sha1": "d68df4214d19", "answer_pdf_sha1": "7ccb5eb08e6d", "source_family": "moex-gov-tw", "moex": {"exam_code": "111190", "c": "506", "s": "0207", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "111", "exam_name": "111年特種考試地方政府公務人員考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "圖書資訊管理"}'::jsonb, NULL),
  ('locality-814ced5a-moex-00068', 'locality-814ced5a', 'locality-814ced5a-moex-111-b3f42868', 'sub-locality-814ced5a-02', NULL, 'single_choice', '在現行國際法秩序中，多數的多邊條約是由國際機構推動，並且監督締約國是否落實條約內容。下列 各項國際條約與專責國際機構的配對，何者正確？', '["國際勞工公約，聯合國經濟、社會和文化權利委員會", "消除對婦女一切形式歧視公約，聯合國消除種族歧視委員會", "難民地位公約，聯合國安全理事會", "公民與政治權利國際公約，聯合國人權事務委員會"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:28+00:00", "source_pdf_sha1": "d68df4214d19", "answer_pdf_sha1": "7ccb5eb08e6d", "source_family": "moex-gov-tw", "moex": {"exam_code": "111190", "c": "506", "s": "0207", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "111", "exam_name": "111年特種考試地方政府公務人員考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "圖書資訊管理"}'::jsonb, NULL),
  ('locality-814ced5a-moex-00069', 'locality-814ced5a', 'locality-814ced5a-moex-111-b3f42868', 'sub-locality-814ced5a-02', NULL, 'single_choice', '新自由主義憑藉市場全球化的發展，促使世界各國政府逐步調整過往的施政方向，大幅自社會福利領 域撤守，宣稱將回歸自由市場開放競爭。在各國政府緊縮社會福利支出時，為捍衛其正當性而強調的 是下列何者？', '["命運共同體", "個人責任", "多元文化", "人性尊嚴"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:28+00:00", "source_pdf_sha1": "d68df4214d19", "answer_pdf_sha1": "7ccb5eb08e6d", "source_family": "moex-gov-tw", "moex": {"exam_code": "111190", "c": "506", "s": "0207", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "111", "exam_name": "111年特種考試地方政府公務人員考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "圖書資訊管理"}'::jsonb, NULL),
  ('locality-814ced5a-moex-00070', 'locality-814ced5a', 'locality-814ced5a-moex-111-b3f42868', 'sub-locality-814ced5a-02', NULL, 'single_choice', '歡歡將自己所收藏的整套《火影忍者》漫畫書，提供給喜喜閱覽，並約定每天以20元計費，30天後 喜喜要將整套漫畫書交還給歡歡，並付600元給歡歡。請問：上述歡歡與喜喜之間所構成的是何種類 型的契約？', '["買賣契約", "租賃契約", "消費借貸契約", "使用借貸契約"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:28+00:00", "source_pdf_sha1": "d68df4214d19", "answer_pdf_sha1": "7ccb5eb08e6d", "source_family": "moex-gov-tw", "moex": {"exam_code": "111190", "c": "506", "s": "0207", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "111", "exam_name": "111年特種考試地方政府公務人員考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "圖書資訊管理"}'::jsonb, NULL),
  ('locality-814ced5a-moex-00071', 'locality-814ced5a', 'locality-814ced5a-moex-111-b3f42868', 'sub-locality-814ced5a-02', NULL, 'single_choice', '關於我國法律修改程序，下列敘述何者正確？', '["法律修正案提出後，必須先送交立法院院會排定法案審查的順序", "法律修正案在一讀會後，若朝野有共識，可逕付相關委員會進行二讀", "法律修正案進入第三讀會，除非內容有重大瑕疵，否則僅能做文字修正", "法律修正案完成三讀程序後，須經立法院院長公布，法案才會正式生效"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:28+00:00", "source_pdf_sha1": "d68df4214d19", "answer_pdf_sha1": "7ccb5eb08e6d", "source_family": "moex-gov-tw", "moex": {"exam_code": "111190", "c": "506", "s": "0207", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "111", "exam_name": "111年特種考試地方政府公務人員考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "圖書資訊管理"}'::jsonb, NULL),
  ('locality-814ced5a-moex-00072', 'locality-814ced5a', 'locality-814ced5a-moex-111-b3f42868', 'sub-locality-814ced5a-02', NULL, 'single_choice', '司法院釋字第791號解釋宣告通姦罪違憲，下列敘述何者正確？', '["國家無介入干預個人性自主之正當性", "通姦行為定義模糊，違反罪刑明確原則", "國家應尊重婚姻家庭之運作，不應課予通姦行為人法律責任", "通姦罪對性自主權的限制手段違反比例原則"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:28+00:00", "source_pdf_sha1": "d68df4214d19", "answer_pdf_sha1": "7ccb5eb08e6d", "source_family": "moex-gov-tw", "moex": {"exam_code": "111190", "c": "506", "s": "0207", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "111", "exam_name": "111年特種考試地方政府公務人員考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "圖書資訊管理"}'::jsonb, NULL),
  ('locality-814ced5a-moex-00073', 'locality-814ced5a', 'locality-814ced5a-moex-111-b3f42868', 'sub-locality-814ced5a-02', NULL, 'single_choice', '關於法律制定與修正程序之敘述，下列何者正確？', '["立法委員不得單獨提出法律修正案至院會討論", "一讀通過後之法案須經黨團協商後方得進入二讀", "總統府及五院得提案，通過程序委員會排案後始進入國會討論", "人民提案經公投通過後，議案即可進入院會討論"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:28+00:00", "source_pdf_sha1": "d68df4214d19", "answer_pdf_sha1": "7ccb5eb08e6d", "source_family": "moex-gov-tw", "moex": {"exam_code": "111190", "c": "506", "s": "0207", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "111", "exam_name": "111年特種考試地方政府公務人員考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "圖書資訊管理"}'::jsonb, NULL),
  ('locality-814ced5a-moex-00074', 'locality-814ced5a', 'locality-814ced5a-moex-111-b3f42868', 'sub-locality-814ced5a-02', NULL, 'single_choice', '應屆國中三年級學生甲，未獲得父母同意即向鄰居機車行老闆乙，宣稱其已獲父母同意訂購機車一輛。 乙依過去與甲一家人之互動經驗確信甲所言為真，故與甲訂定買賣契約。下列敘述何者正確？', '["甲未獲父母同意訂購機車，因此本買賣契約應為無效", "本契約無效，因此甲不需對乙負任何法律責任", "因乙未用盡一切方法確認甲所言是否正確，故甲並未因此有債務", "即使契約效力未定，但若乙因此有損失則可要求甲損害賠償"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:28+00:00", "source_pdf_sha1": "d68df4214d19", "answer_pdf_sha1": "7ccb5eb08e6d", "source_family": "moex-gov-tw", "moex": {"exam_code": "111190", "c": "506", "s": "0207", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "111", "exam_name": "111年特種考試地方政府公務人員考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "圖書資訊管理"}'::jsonb, NULL),
  ('locality-814ced5a-moex-00075', 'locality-814ced5a', 'locality-814ced5a-moex-111-b3f42868', 'sub-locality-814ced5a-02', NULL, 'single_choice', '丁男因精神疾病受監護宣告，一日情緒失控將鄰居庚毆成重傷。下列敘述何者正確？', '["丁因患有精神疾病，得減輕或免除刑責", "丁之監護人原則上對庚有賠償責任", "因丁無行為能力，故加害行為免除刑責", "丁不需賠償庚，丁之監護人才有賠償責任"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:28+00:00", "source_pdf_sha1": "d68df4214d19", "answer_pdf_sha1": "7ccb5eb08e6d", "source_family": "moex-gov-tw", "moex": {"exam_code": "111190", "c": "506", "s": "0207", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "111", "exam_name": "111年特種考試地方政府公務人員考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "圖書資訊管理"}'::jsonb, NULL)
